def fetch_prisma_schema(url: str) -> str:
    r = requests.get(url)
    if r.status_code != 200:
        raise Exception(f"Failed to fetch schema: {r.status_code}")
    return r.text


def parse_prisma_model(model_text: str) -> dict:
    lines = model_text.strip().split("\n")
    model_name = lines[0].split()[1]

    required, optional = [], []
    field_types, unique_fields = {}, []

    dtypes = {"String","Int","BigInt","Float","Decimal","Boolean","DateTime","Json"}

    for line in lines[1:]:
        line = line.strip()
        if not line or line.startswith("//") or line in ("}",):
            continue

        m = re.match(r"(\w+)\s+(\w+\??)(.*)", line)
        if not m:
            continue

        name, ftype, attrs = m.groups()

        base = ftype.replace("?", "").replace("[]", "")

        if base not in dtypes and base[0].isupper():
            continue

        is_optional = "?" in ftype or "@default" in attrs

        (optional if is_optional else required).append(name)

        if base in ["String"]:
            vtype = "string"
        elif base in ["Int", "BigInt"]:
            vtype = "integer"
        elif base in ["Float", "Decimal"]:
            vtype = "decimal"
        elif base == "Boolean":
            vtype = "boolean"
        elif base == "DateTime":
            vtype = "timestamp"
        else:
            vtype = "string"

        field_types[name] = vtype

        if "@unique" in attrs:
            unique_fields.append(name)

    return {
        "model_name": model_name,
        "required_fields": required,
        "optional_fields": optional,
        "field_types": field_types,
        "unique_fields": unique_fields
    }


def parse_prisma_schema(schema_text: str) -> dict:
    models = re.findall(r"model\s+\w+\s*{[^}]*}", schema_text, re.DOTALL)
    parsed = {}

    for m in models:
        model = parse_prisma_model(m)
        parsed[model["model_name"]] = model

    return parsed


print("Fetching prisma schema...")
PRISMA_MODELS = parse_prisma_schema(fetch_prisma_schema(PRISMA_SCHEMA_URL))

print(f"Loaded {len(PRISMA_MODELS)} prisma models")

def discover_csv_files():
    try:
        files = mssparkutils.fs.ls(csv_base_path)

        return [
            {
                "table_name": f.name.replace(".csv", ""),
                "csv_path": f.name,
                "full_path": f.path
            }
            for f in files
            if f.name.endswith(".csv") and not f.name.startswith("_")
        ]
    except Exception as e:
        print(f"Discovery failed: {e}")
        return []


csv_files = discover_csv_files()

if not csv_files:
    raise Exception("No csv files found")

print(f"Found {len(csv_files)} cvs files")

def validate_csv(csv_path, table_name, model):
    errors = []

    df = spark.read.option("header", True).csv(f"{csv_base_path}/{csv_path}")

    row_count = df.count()

    if row_count == 0:
        return [f"{table_name}: empty file"], 0

    cols = set(df.columns)
    required = set(model["required_fields"])

    # Missing fields
    missing = required - cols
    if missing:
        errors.append(f"{table_name}: missing required {missing}")

    # Unexpected fields
    expected = set(model["required_fields"] + model["optional_fields"])
    unexpected = cols - expected
    if unexpected:
        errors.append(f"{table_name}: unexpected columns {unexpected}")

    # Null checks
    for f in required:
        if f in cols:
            nulls = df.filter(F.col(f).isNull() | (F.col(f) == "")).count()
            if nulls:
                errors.append(f"{table_name}: {f} has {nulls} nulls")

    # Primary key uniqueness
    if "id" in cols:
        if row_count != df.select("id").distinct().count():
            errors.append(f"{table_name}: duplicate IDs")

    return errors, row_count

all_errors = []
entity_row_counts = {}

print("Running validation...")

for f in csv_files:

    model = PRISMA_MODELS.get(f["table_name"])

    if not model:
        model = {
            "required_fields": ["id"],
            "optional_fields": [],
            "field_types": {"id": "string"},
            "unique_fields": ["id"]
        }

    errors, row_count = validate_csv(
        f["csv_path"],
        f["table_name"],
        model
    )

    all_errors.extend(errors)
    entity_row_counts[f["table_name"]] = row_count

    if errors:
        print(f"{f['table_name']}: {len(errors)} errors ({row_count:,} rows)")
    else:
        print(f"{f['table_name']}: passed ({row_count:,} rows)")


print(f"Files: {len(csv_files)}")
print(f"Errors: {len(all_errors)}")

if all_errors:
    for e in all_errors:
        print("Errors: ", e)
    raise Exception("Validation failed")
else:
    print("All validations have successfully passed")
